    fn smart_broadcast_routes_vacuum_to_vacuum_path() {
        let result = smart_broadcast(BuleyProjection::VACUUM, 3, tower_ceilings::HEXON);
        assert!(matches!(result, Ok(BroadcastResult::Vacuum(_))));
    }

