    fn smart_broadcast_routes_nonvacuum_to_costly_path() {
        let b = BuleyProjection {
            waste: 2,
            opportunity: 1,
            diversity: 0,
        };
        let result = smart_broadcast(b, 2, 12);
        assert!(matches!(result, Ok(BroadcastResult::Costly(_))));
    }

